import { getStoredTaxRate, parsePrice } from "./taxUtils.js";
import { showTooltip, hideTooltip } from "./tooltip.js";

document.addEventListener("mouseup", async () => {
  const selection = window.getSelection();
  if (!selection || selection.rangeCount === 0) {
    console.log("No selection found");
    hideTooltip();
    return;
  }

  let text = "";
  for (let i = 0; i < selection.rangeCount; i++) {
    text += selection.getRangeAt(i).toString();
  }
  console.log(`Selected text: "${text.trim()}"`);

  const price = parsePrice(text.trim());
  if (price === null) {
    console.warn("No valid price found in selection");
    hideTooltip();
    return;
  }

  const taxRate = await getStoredTaxRate();
  if (taxRate === null) {
    console.warn("Tax rate is null — tooltip will ask user to set tax settings");
    showTooltip(window.scrollX + 10, window.scrollY + 10, "Please set tax settings first");
    return;
  }

  const afterTax = (price * (1 + taxRate)).toFixed(2);
  const range = selection.getRangeAt(0);
  const rect = range.getBoundingClientRect();
  const x = rect.left + window.scrollX + rect.width / 2;
  const y = rect.bottom + window.scrollY + 5;
  console.log(`Price: ${price}, Tax rate: ${taxRate}, After tax: ${afterTax}`);
  showTooltip(x, y, `After tax: $${afterTax}`);
});

document.addEventListener("mousedown", () => {
  console.log("Mouse down - hiding tooltip");
  hideTooltip();
});
